from sortedcontainers import SortedList
import heapq
from collections import defaultdict
class ReservationSystem:
    def __init__(self,rooms):
        self.room_to_times = {room: SortedList() for room in rooms}
        self.reservation_id = 0

    def scheduleMeeting(self,start_time,end_time) -> int:
        if start_time < 0 or end_time < 0:
            raise Exception('time can not be negative')
        elif end_time < start_time:
            raise Exception('end time can not be larger than start time')

        for room,times in self.room_to_times.items():
            start = times.bisect_left(start_time)
            end = times.bisect_left(end_time)
            if start%2 == 0 and start == end:
                self.room_to_times[room].update([start_time,end_time])
                return f"Reservation made: Room={room} time= [{start_time},{end_time}]"

        raise Exception(f'No Rooms available at time,[{start_time},{end_time}]')


def main():
    rooms = ['roomA','roomB','roomC']
    reservation_system = ReservationSystem(rooms)
    for s,e in [[1,5],[1,5],[1,5],[1,5],[1,2],[0,1],[0,1]]:
        try:
            print(reservation_system.scheduleMeeting(s,e))
        except Exception as e:
            print(e)


if __name__ == '__main__':
    main()

