import java.util.HashMap;
import java.util.TreeMap;

class RoomReservation{

    TreeMap<Integer , Integer> reservation = new TreeMap<>();
    String room = null;

    public RoomReservation(String room) {
        this.room = room;
    }

    public boolean scheduleMeeting(int startTime , int endTime){
        if (startTime < 0 || endTime < 0 ){
            System.out.println("Rooms not avaliable please enter valid start and end time");
            return (false);
        }

        var left = reservation.floorEntry(startTime);
        var right =reservation.ceilingEntry(endTime);
        //chech for meeting empty slot
        if(left != null && right != null){
            if(startTime  > left.getValue() && endTime < right.getKey()){
                reservation.put(startTime, endTime);
                return (true);
            }
        }

        if(left == null && right == null){
            reservation.put(startTime, endTime);
            return (true);
        }


        if (left  == null && endTime < right.getKey()){
            reservation.put(startTime, endTime);
            return (true);
        }

        if (right == null && startTime > left.getValue()){
            reservation.put(startTime, endTime);
            return (true);
        }

        System.out.println("Sorry Someone else has booked the room before you");
        return (false);

    }


}

class RoomDirectory{
    HashMap<String , RoomReservation> roomDirectory = new HashMap<>();

    public RoomDirectory(String[] rooms) {
        for(int i = 0 ; i < rooms.length ; i++){
            roomDirectory.put(rooms[i], new RoomReservation(rooms[i]));
        }
    }

    public RoomReservation getRoom(String room){
        return  roomDirectory.get(room);
    }


}

